# normalize ids
norm = lambda s: None if s is None else str(s).strip().lstrip('#')
for col in ['Product2Id','PricebookEntryId','QuoteId','Id']:
    if col in ql.columns:
        ql[col+'_n'] = ql[col].map(norm)
for col in ['Id','Product2Id','Pricebook2Id']:
    if col in pbe.columns:
        pbe[col+'_n'] = pbe[col].map(norm)

# join to get catalog unit price
m = ql.merge(pbe, left_on='PricebookEntryId_n', right_on='Id_n', how='left', suffixes=('','_pbe'))

# find any lines where UnitPrice != catalog UnitPrice (and discount is 0 to avoid intended discount logic)
