if (m['Discount_f'] >= 10).any():
    violations.append('high_discount')
# 3) unusually high quantity (>= 25 maybe)
if (m['Quantity'].astype(float) >= 25).any():
    violations.append('high_quantity')

# load knowledge articles file
path = var_call_1eLbJ9htEqIynFwBq64OVWmX
with open(path,'r',encoding='utf-8') as f:
    kav = pd.DataFrame(json.load(f))

# pick best matching knowledge article based on keywords
text_cols = ['title','summary','faq_answer__c','urlname']

def score_row(row):
    hay = ' '.join([str(row.get(c,'')) for c in text_cols]).lower()
    score = 0
    if 'discount' in hay:
        score += 2
    if 'maximum' in hay or 'max' in hay:
        score += 1
    if '15%' in hay or '15 %' in hay:
        score += 2
    if 'approval' in hay or 'manager' in hay:
        score += 1
    if 'pricebook' in hay or 'unit price' in hay:
        score += 1
    if 'quantity' in hay:
        score += 1
    if 'bulk' in hay:
        score += 1
    if 'quote' in hay:
        score += 1
    return score

kav['score'] = kav.apply(score_row, axis=1)
